sourcesContent:
import styled from 'styled-components';
import colors from '../constants/colors';
import fontSizes from '../constants/fontsize';
import SectionTitle from '../components/SectionTitle';
import { ContactCard, FeatureCard, StatCard } from '../components/Cards';

const pageStats = [
  { value: '4', label: 'Business divisions' },
  { value: 'Expert', label: 'Professional team' },
  { value: '100+', label: 'Trusted partners' },
  { value: '100%', label: 'Client satisfaction' },
];

const companyCards = [
  {
    id: '01',
    title: 'Lucky Builders and Development',
    text: 'Construction, development, and project management solutions with a focus on quality, safety, and long-term value.',
    tags: ['Residential', 'Commercial', 'Project Planning'],
  },
  {
    id: '02',
    title: 'Lucky Global Holdings Limited',
    text: 'Strategic investments, business development, and long-term value creation across growth sectors.',
    tags: ['Investments', 'Portfolio Growth', 'Strategy'],
  },
  {
    id: '03',
    title: 'Kraji Global Trading SMC Pvt. Ltd.',
    text: 'International trading solutions for professional sourcing, procurement, and supply chain execution.',
    tags: ['Import/Export', 'Procurement', 'Supply Chain'],
  },
  {
    id: '04',
    title: 'Lucky Global Traders',
    text: 'A trading company connecting suppliers and customers with efficient procurement and competitive pricing.',
    tags: ['Wholesale', 'Logistics', 'Market Access'],
  },
];

const timelineItems = [
  {
    year: '2011',
    title: 'Lucky Group established',
    text: 'The group started with a clear vision to build a diversified business platform with a lasting impact.',
  },
  {
    year: '2015',
    title: 'Trading arm expanded',
    text: 'New relationships and market access opened the door to wider sourcing and distribution.',
  },
  {
    year: '2020',
    title: 'Construction division launched',
    text: 'Development and construction services were formalized to support the group’s real-world projects.',
  },
  {
    year: 'Today',
    title: 'Four pillars, one vision',
    text: 'The group now operates across investments, construction, trading, and business development.',
  },
];

const advantageItems = [
  {
    icon: '★',
    title: 'Excellence of Quality',
    text: 'Every project and transaction is handled with structured execution, careful oversight, and consistent standards.',
  },
  {
    icon: '◌',
    title: 'Innovation at Growth',
    text: 'We adapt across sectors with flexible systems, practical solutions, and market-aware decision-making.',
  },
  {
    icon: '◆',
    title: 'Experienced Professionals',
    text: 'Our team blends field experience with strategic thinking to deliver dependable outcomes.',
  },
  {
    icon: '✦',
    title: 'Customer Satisfaction',
    text: 'Client trust is built through responsive communication, transparent delivery, and measurable progress.',
  },
];

const contactItems = [
  {
    label: 'Phone Numbers',
    title: 'Call our team',
    text: '+92 311 123 4567\n+92 301 000 0000',
  },
  {
    label: 'Emails',
    title: 'Official inboxes',
    text: 'info@luckygroup.com\nbusiness@luckygroup.com',
  },
  {
    label: 'Address',
    title: 'Head office',
    text: 'Lahore, Pakistan\nCentral business district',
  },
  {
    label: 'Hours',
    title: 'Business timing',
    text: 'Mon-Fri: 9:00 AM - 6:00 PM\nSaturday: 9:00 AM - 2:00 PM',
  },
];

const Page = styled.main`
  background: ${colors.whitePure};
`;

const Section = styled.section`
  padding: ${({ $dense }) => ($dense ? '4rem 1.5rem' : '6rem 1.5rem')};
  background: ${({ $variant }) => {
    if ($variant === 'dark') return colors.navy;
    if ($variant === 'cream') return '#f7f4ec';
    return colors.whitePure;
  }};
  color: ${({ $variant }) => ($variant === 'dark' ? colors.whitePure : colors.textBody)};

  @media (max-width: 768px) {
    padding: ${({ $dense }) => ($dense ? '3rem 1.1rem' : '4.5rem 1.1rem')};
  }
`;

const Container = styled.div`
  max-width: 1200px;
  margin: 0 auto;
`;

const Hero = styled.section`
  padding: 3rem 1.5rem 5rem;
  background:
    linear-gradient(180deg, rgba(10, 22, 40, 0.98), rgba(10, 22, 40, 0.96)),
    radial-gradient(circle at left top, rgba(201, 168, 76, 0.18), transparent 35%);
  color: ${colors.whitePure};
`;

const HeroGrid = styled.div`
  max-width: 1200px;
  margin: 0 auto;
  display: grid;
  grid-template-columns: minmax(0, 1.2fr) minmax(320px, 0.9fr);
  gap: 3rem;
  align-items: center;

  @media (max-width: 980px) {
    grid-template-columns: 1fr;
  }
`;

const Eyebrow = styled.span`
  display: inline-flex;
  align-items: center;
  gap: 0.6rem;
  text-transform: uppercase;
  letter-spacing: 0.3em;
  color: ${colors.goldLight};
  font-size: ${fontSizes.xs};
  margin-bottom: 1.2rem;

  &::before {
    content: '';
    width: 2.5rem;
    height: 1px;
    background: ${colors.goldLight};
  }
`;

const HeroTitle = styled.h1`
  margin: 0;
  max-width: 12ch;
  font-size: clamp(2.85rem, 4.3vw, 3.55rem);
  line-height: 0.98;
  letter-spacing: -0.035em;

  span {
    color: ${colors.goldLight};
  }
`;

const HeroText = styled.p`
  max-width: 36rem;
  margin: 1.35rem 0 0;
  color: rgba(245, 245, 245, 0.76);
  line-height: 1.75;
  font-size: ${fontSizes.md};
`;

const ActionRow = styled.div`
  display: flex;
  flex-wrap: wrap;
  gap: 1rem;
  margin-top: 2rem;
`;

const Button = styled.a`
  padding: 0.95rem 1.35rem;
  border-radius: 999px;
  font-weight: 700;
  font-size: ${fontSizes.sm};
  border: 1px solid ${({ $ghost }) => ($ghost ? 'rgba(255,255,255,0.18)' : 'transparent')};
  background: ${({ $ghost }) => ($ghost ? 'transparent' : colors.gold)};
  color: ${({ $ghost }) => ($ghost ? colors.whitePure : colors.navy)};
`;

const HeroPanel = styled.div`
  position: relative;
  min-height: 26rem;
  padding: 2rem;
  border-radius: 1.5rem;
  background:
    linear-gradient(180deg, rgba(26, 45, 79, 0.55), rgba(10, 22, 40, 0.92)),
    linear-gradient(145deg, rgba(201, 168, 76, 0.12), transparent 50%);
  border: 1px solid rgba(255, 255, 255, 0.08);
  overflow: hidden;

  &::before {
    content: '';
    position: absolute;
    inset: 10% 12% auto auto;
    width: 10rem;
    height: 10rem;
    border: 1px solid rgba(232, 213, 163, 0.18);
    border-radius: 50%;
  }

  &::after {
    content: '';
    position: absolute;
    inset: auto auto 12% 14%;
    width: 55%;
    height: 1px;
    background: linear-gradient(90deg, transparent, rgba(201, 168, 76, 0.45), transparent);
  }
`;

const HeroBars = styled.div`
  position: absolute;
  inset: 10rem 2rem 3rem;
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  align-items: end;
  gap: 0.9rem;

  span {
    border-radius: 0.9rem 0.9rem 0 0;
    border: 1px solid rgba(201, 168, 76, 0.3);
    background: linear-gradient(180deg, rgba(26, 45, 79, 0.85), rgba(201, 168, 76, 0.2));
  }

  span:nth-child(1) {
    height: 34%;
  }

  span:nth-child(2) {
    height: 58%;
  }

  span:nth-child(3) {
    height: 78%;
  }

  span:nth-child(4) {
    height: 48%;
  }
`;

const HeroBadge = styled.div`
  position: absolute;
  right: 1.8rem;
  bottom: 1.8rem;
  width: 7rem;
  height: 7rem;
  border-radius: 1.2rem;
  background: ${colors.gold};
  color: ${colors.navy};
  display: grid;
  place-items: center;
  text-align: center;
  font-weight: 800;
  box-shadow: 0 18px 40px rgba(201, 168, 76, 0.25);

  small {
    display: block;
    font-size: ${fontSizes.xxs};
    letter-spacing: 0.18em;
    text-transform: uppercase;
    margin-top: 0.2rem;
  }
`;

const StatsRow = styled.div`
  display: grid;
  grid-template-columns: repeat(4, minmax(0, 1fr));
  gap: 1rem;
  margin-top: 2rem;

  @media (max-width: 768px) {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }
`;

const AboutGrid = styled.div`
  display: grid;
  grid-template-columns: minmax(0, 0.95fr) minmax(0, 1.05fr);
  gap: 3rem;
  align-items: center;

  @media (max-width: 980px) {
    grid-template-columns: 1fr;
  }
`;

const Illustration = styled.div`
  position: relative;
  min-height: 31rem;
  border-radius: 1.2rem;
  background: ${colors.navy};
  box-shadow: 0 20px 50px rgba(10, 22, 40, 0.18);
  overflow: hidden;
  border: 1px solid rgba(255, 255, 255, 0.05);

  .seal {
    position: absolute;
    top: 18%;
    left: 50%;
    transform: translateX(-50%);
    width: 8rem;
    height: 8rem;
    border-radius: 50%;
    border: 1px solid rgba(201, 168, 76, 0.35);
    display: grid;
    place-items: center;
    color: ${colors.goldLight};
    font-size: ${fontSizes.xl};
    font-weight: 800;
  }

  .bar {
    position: absolute;
    bottom: 8%;
    width: 15%;
    background: linear-gradient(180deg, rgba(26, 45, 79, 0.9), rgba(201, 168, 76, 0.45));
    border: 1px solid rgba(201, 168, 76, 0.22);
  }

  .bar.one { left: 13%; height: 24%; }
  .bar.two { left: 30%; height: 36%; }
  .bar.three { left: 47%; height: 50%; }
  .bar.four { left: 64%; height: 32%; }

  .tag {
    position: absolute;
    right: 10%;
    bottom: 10%;
    width: 7rem;
    height: 7rem;
    border-radius: 1rem;
    background: ${colors.gold};
    color: ${colors.navy};
    display: grid;
    place-items: center;
    font-weight: 800;
    text-align: center;
    box-shadow: 0 15px 30px rgba(201, 168, 76, 0.25);
  }
`;

const AboutList = styled.div`
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 1rem;
  margin-top: 1.8rem;

  @media (max-width: 620px) {
    grid-template-columns: 1fr;
  }
`;

const AboutPoint = styled.div`
  display: flex;
  gap: 0.85rem;
  align-items: flex-start;
  padding: 1rem 1rem 1rem 0;

  .dot {
    width: 0.9rem;
    height: 0.9rem;
    border-radius: 50%;
    margin-top: 0.45rem;
    background: ${colors.gold};
    box-shadow: 0 0 0 6px rgba(201, 168, 76, 0.12);
    flex: 0 0 auto;
  }

  h4 {
    margin: 0 0 0.35rem;
    color: ${colors.navy};
    font-size: ${fontSizes.sm};
  }

  p {
    margin: 0;
    color: ${colors.grayMid};
    line-height: 1.75;
  }
`;

const TimelineGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 1.2rem 2rem;

  @media (max-width: 720px) {
    grid-template-columns: 1fr;
  }
`;

const TimelineItem = styled.article`
  padding-left: 1.15rem;
  border-left: 2px solid rgba(201, 168, 76, 0.35);

  .year {
    font-size: ${fontSizes.xxs};
    letter-spacing: 0.2em;
    text-transform: uppercase;
    color: ${colors.gold};
    margin-bottom: 0.6rem;
  }

  h3 {
    margin: 0 0 0.5rem;
    font-size: ${fontSizes.md};
    color: ${colors.navy};
  }

  p {
    margin: 0;
    color: ${colors.grayMid};
    line-height: 1.7;
  }
`;

const CompaniesGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 1rem;

  @media (max-width: 860px) {
    grid-template-columns: 1fr;
  }
`;

const CompanyCard = styled.article`
  position: relative;
  padding: 1.35rem;
  border-radius: 1.25rem;
  background: ${colors.whitePure};
  border: 1px solid ${colors.grayLight};
  box-shadow: 0 18px 42px ${colors.shadowSoft};
  overflow: hidden;

  .number {
    position: absolute;
    top: 1rem;
    right: 1rem;
    font-size: ${fontSizes.xl};
    font-weight: 800;
    color: rgba(10, 22, 40, 0.08);
  }

  h3 {
    margin: 0 0 0.7rem;
    font-size: ${fontSizes.md};
    color: ${colors.navy};
  }

  p {
    margin: 0;
    color: ${colors.grayMid};
    line-height: 1.75;
  }
`;

const Tags = styled.div`
  display: flex;
  flex-wrap: wrap;
  gap: 0.55rem;
  margin-top: 1rem;

  span {
    padding: 0.45rem 0.7rem;
    border-radius: 999px;
    background: rgba(201, 168, 76, 0.12);
    color: ${colors.goldDark};
    font-size: ${fontSizes.xs};
  }
`;

const AdvantageGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(4, minmax(0, 1fr));
  gap: 1rem;

  @media (max-width: 1100px) {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }

  @media (max-width: 640px) {
    grid-template-columns: 1fr;
  }
`;

const MissionGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 1rem;

  @media (max-width: 860px) {
    grid-template-columns: 1fr;
  }
`;

const MissionCard = styled.article`
  position: relative;
  padding: 1.6rem;
  border-radius: 1.2rem;
  min-height: 15rem;
  overflow: hidden;
  color: ${({ $alt }) => ($alt ? colors.navy : colors.whitePure)};
  background: ${({ $alt }) => ($alt ? colors.gold : colors.navy)};

  .eyebrow {
    display: inline-flex;
    gap: 0.5rem;
    align-items: center;
    letter-spacing: 0.18em;
    text-transform: uppercase;
    font-size: ${fontSizes.xxs};
    margin-bottom: 1rem;
    color: ${({ $alt }) => ($alt ? colors.navyMid : colors.goldLight)};
  }

  h3 {
    margin: 0 0 0.8rem;
    font-size: ${fontSizes.lg};
    line-height: 1.2;
  }

  p {
    margin: 0;
    line-height: 1.8;
    color: ${({ $alt }) => ($alt ? 'rgba(10, 22, 40, 0.82)' : 'rgba(245, 245, 245, 0.8)')};
  }
`;

const ContactGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(4, minmax(0, 1fr));
  gap: 1rem;

  @media (max-width: 1100px) {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }

  @media (max-width: 620px) {
    grid-template-columns: 1fr;
  }
`;

const Footer = styled.footer`
  background: ${colors.navy};
  color: rgba(245, 245, 245, 0.8);
  padding: 3.5rem 1.5rem 1.5rem;
  border-top: 1px solid rgba(255, 255, 255, 0.06);
`;

const FooterGrid = styled.div`
  max-width: 1200px;
  margin: 0 auto;
  display: grid;
  grid-template-columns: 1.1fr 0.8fr 0.8fr 0.9fr;
  gap: 2rem;

  @media (max-width: 980px) {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }

  @media (max-width: 640px) {
    grid-template-columns: 1fr;
  }
`;

const FooterBrand = styled.div`
  .logo {
    display: inline-flex;
    align-items: center;
    gap: 0.75rem;
    font-weight: 700;
    color: ${colors.whitePure};
    margin-bottom: 1rem;
  }

  .mark {
    width: 2rem;
    height: 2rem;
    border-radius: 0.6rem;
    background: ${colors.gold};
    color: ${colors.navy};
    display: grid;
    place-items: center;
  }

  p {
    margin: 0;
    line-height: 1.8;
  }
`;

const FooterLinks = styled.div`
  h4 {
    margin: 0 0 1rem;
    color: ${colors.goldLight};
    font-size: ${fontSizes.sm};
  }

  a,
  p {
    display: block;
    margin: 0 0 0.7rem;
    line-height: 1.6;
    color: rgba(245, 245, 245, 0.75);
  }
`;

export default function HomePage() {
  return (
    <Page id="home">
      <Hero>
        <Container>
          <Eyebrow>Diversified Business Group</Eyebrow>
          <HeroGrid>
            <div>
              <HeroTitle>
                Building <span>Excellence</span> Across Industries
              </HeroTitle>
              <HeroText>
                Lucky Group of Companies is a diversified organization delivering reliable solutions in construction,
                investments, trading, and business development with a focus on sustainable growth.
              </HeroText>
              <ActionRow>
                <Button href="#companies">Explore Companies</Button>
                <Button href="#contact" $ghost>
                  Contact Us
                </Button>
              </ActionRow>

              <StatsRow>
                {pageStats.map((item) => (
                  <StatCard key={item.label}>
                    <strong>{item.value}</strong>
                    <span>{item.label}</span>
                  </StatCard>
                ))}
              </StatsRow>
            </div>

      
          </HeroGrid>
        </Container>
      </Hero>

      <Section id="about">
        <Container>
          <AboutGrid>
            <Illustration aria-hidden="true">
              <div className="seal">LG</div>
              <div className="bar one" />
              <div className="bar two" />
              <div className="bar three" />
              <div className="bar four" />
              <div className="tag">
                10+<br />
                Years
              </div>
            </Illustration>

            <div>
              <SectionTitle
                align="left"
                compact
                eyebrow="About Us"
                title="A legacy of trust and innovation"
                subtitle="Lucky Group of Companies is a diversified business group operating across specialized subsidiaries, combining sector experience with disciplined execution."
              />

              <AboutList>
                <AboutPoint>
                  <span className="dot" />
                  <div>
                    <h4>Construction</h4>
                    <p>Residential and commercial building solutions focused on long-term value.</p>
                  </div>
                </AboutPoint>
                <AboutPoint>
                  <span className="dot" />
                  <div>
                    <h4>Investments</h4>
                    <p>Capital deployment and business growth opportunities with strong governance.</p>
                  </div>
                </AboutPoint>
                <AboutPoint>
                  <span className="dot" />
                  <div>
                    <h4>Global Trade</h4>
                    <p>Procurement and sourcing services that support efficient market access.</p>
                  </div>
                </AboutPoint>
                <AboutPoint>
                  <span className="dot" />
                  <div>
                    <h4>Partnerships</h4>
                    <p>Long-term relationships built on communication, quality, and reliability.</p>
                  </div>
                </AboutPoint>
              </AboutList>
            </div>
          </AboutGrid>
        </Container>
      </Section>

      <Section $variant="cream">
        <Container>
          <SectionTitle
            eyebrow="Our Journey"
            title="Growth through the years"
            subtitle="From a focused foundation to a broader group vision, every milestone reflects commitment to excellence and sustainable progress."
          />

          <TimelineGrid>
            {timelineItems.map((item) => (
              <TimelineItem key={item.year}>
                <div className="year">{item.year}</div>
                <h3>{item.title}</h3>
                <p>{item.text}</p>
              </TimelineItem>
            ))}
          </TimelineGrid>
        </Container>
      </Section>

      <Section id="companies">
        <Container>
          <SectionTitle
            eyebrow="Group Companies"
            title="Our business subsidiaries"
            subtitle="Each company contributes a specialized capability, allowing the group to deliver comprehensive solutions across sectors."
          />

          <CompaniesGrid>
            {companyCards.map((company) => (
              <CompanyCard key={company.id}>
                <div className="number">{company.id}</div>
                <h3>{company.title}</h3>
                <p>{company.text}</p>
                <Tags>
                  {company.tags.map((tag) => (
                    <span key={tag}>{tag}</span>
                  ))}
                </Tags>
              </CompanyCard>
            ))}
          </CompaniesGrid>
        </Container>
      </Section>

      <Section id="why-us" $variant="dark">
        <Container>
          <SectionTitle
            eyebrow="Why Choose Us"
            title="The Lucky Group advantage"
            subtitle="We combine broad reach with local understanding, backed by experienced professionals who put client success at the center of everything we do."
          />

          <AdvantageGrid>
            {advantageItems.map((item) => (
              <FeatureCard key={item.title}>
                <div className="icon">{item.icon}</div>
                <h3>{item.title}</h3>
                <p>{item.text}</p>
              </FeatureCard>
            ))}
          </AdvantageGrid>
        </Container>
      </Section>

      <Section $variant="cream">
        <Container>
          <SectionTitle
            eyebrow="Our Purpose"
            title="Vision and mission"
            subtitle="Clear direction keeps the group aligned across sectors, partnerships, and long-term development goals."
          />

          <MissionGrid>
            <MissionCard>
              <div className="eyebrow">Our Vision</div>
              <h3>To become a trusted global business group creating sustainable growth.</h3>
              <p>
                We aim to be recognized worldwide as a diversified business group that delivers excellence across every
                industry we serve.
              </p>
            </MissionCard>

            <MissionCard $alt>
              <div className="eyebrow">Our Mission</div>
              <h3>To provide innovative solutions and foster long-term relationships.</h3>
              <p>
                Our mission is to deliver investments, trading, and construction services that create meaningful value
                through professional execution and community-focused growth.
              </p>
            </MissionCard>
          </MissionGrid>
        </Container>
      </Section>

      <Section id="contact">
        <Container>
          <SectionTitle
            eyebrow="Get In Touch"
            title="Contact Lucky Group"
            subtitle="Whether you are a client, investor, or business partner, we would be glad to hear from you."
          />

          <ContactGrid>
            {contactItems.map((item) => (
              <ContactCard key={item.label}>
                <div className="label">{item.label}</div>
                <h3>{item.title}</h3>
                <p>{item.text}</p>
              </ContactCard>
            ))}
          </ContactGrid>
        </Container>
      </Section>

      <Footer>
        <FooterGrid>
          <FooterBrand>
            <div className="logo">
              <span className="mark">LG</span>
              <span>Lucky Group of Companies</span>
            </div>
            <p>
              A diversified business group delivering construction, investments, trading, and business development with
              a focus on quality and sustainable growth.
            </p>
          </FooterBrand>

          <FooterLinks>
            <h4>Quick Links</h4>
            <a href="#about">About Us</a>
            <a href="#companies">Group Companies</a>
            <a href="#why-us">Why Choose Us</a>
            <a href="#contact">Contact</a>
          </FooterLinks>

          <FooterLinks>
            <h4>Our Companies</h4>
            <p>Lucky Builders and Development</p>
            <p>Lucky Global Holdings Limited</p>
            <p>Kraji Global Trading SMC Pvt. Ltd.</p>
            <p>Lucky Global Traders</p>
          </FooterLinks>

          <FooterLinks>
            <h4>Contact</h4>
            <p>+92 311 123 4567</p>
            <p>info@luckygroup.com</p>
            <p>Lahore, Pakistan</p>
            <p>Mon-Fri, 9:00 AM - 6:00 PM</p>
          </FooterLinks>
        </FooterGrid>
      </Footer>
    </Page>
  );
}
